#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-12
#
# test-output-guard-dispatcher.sh — end-to-end test for #1794 dispatcher output guard.
#
# Validates that src/hooks/bin/run-hook.mjs (the actual production dispatcher)
# strips hookEventName='UserPromptSubmit' and additionalContext from stdout when
# the firing event is a lifecycle event (WorktreeCreate, WorktreeRemove, etc.).
#
# Why end-to-end (not unit): the existing vitest test calls sanitizeOutput()
# directly. This test pipes JSON into the actual run-hook.mjs binary, asserting
# the WIRING — not just the function — works. If someone refactors run-hook.mjs
# and forgets the sanitizeOutput() call site, this test catches it.
#
# Exit codes: 0 = all assertions passed, 1 = any failed.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
RUN_HOOK="$REPO_ROOT/src/hooks/bin/run-hook.mjs"

if [[ ! -f "$RUN_HOOK" ]]; then
  echo "ERROR: run-hook.mjs not found at $RUN_HOOK" >&2
  exit 1
fi

# Tee stderr (dispatcher WARN lines + jq errors on missing paths) to a tmp log
# we can inspect on test failure rather than silencing it on the line.
STDERR_LOG="$(mktemp -t hook-dispatch-stderr.XXXXXX.log)"
trap 'rm -f "$STDERR_LOG"' EXIT

PASS=0
FAIL=0

red()   { printf '\033[0;31m%s\033[0m' "$1"; }
green() { printf '\033[0;32m%s\033[0m' "$1"; }

assert_no_field() {
  local label="$1"
  local stdout="$2"
  local field="$3"
  if echo "$stdout" | jq -e ".hookSpecificOutput.${field}" >/"$STDERR_LOG" 2>>"$STDERR_LOG"; then
    printf "  %s %s — stdout still has hookSpecificOutput.%s: %s\n" \
      "$(red FAIL)" "$label" "$field" "$(echo "$stdout" | jq -c .hookSpecificOutput)"
    FAIL=$((FAIL + 1))
    return 1
  else
    printf "  %s %s — hookSpecificOutput.%s absent from stdout\n" \
      "$(green PASS)" "$label" "$field"
    PASS=$((PASS + 1))
    return 0
  fi
}

assert_field_equals() {
  local label="$1"
  local stdout="$2"
  local path="$3"
  local expected="$4"
  local actual
  actual=$(echo "$stdout" | jq -r "$path" 2>>"$STDERR_LOG")
  if [[ "$actual" == "$expected" ]]; then
    printf "  %s %s — %s == %s\n" "$(green PASS)" "$label" "$path" "$expected"
    PASS=$((PASS + 1))
    return 0
  else
    printf "  %s %s — %s expected %s, got %s\n" \
      "$(red FAIL)" "$label" "$path" "$expected" "$actual"
    FAIL=$((FAIL + 1))
    return 1
  fi
}

run_dispatcher() {
  local hook_name="$1"
  local input="$2"
  # stderr is captured to $STDERR_LOG (dispatcher prints WARN lines, telemetry, etc.).
  # Stdout is what CC reads — that's what we assert on.
  echo "$input" | node "$RUN_HOOK" "$hook_name" 2>>"$STDERR_LOG"
}

# ---------------------------------------------------------------------------
# Test 1: WorktreeCreate command-type emits the BARE provisioned path (#2335)
# ---------------------------------------------------------------------------
echo "Test 1: WorktreeCreate command-type — bare path stdout (#2335 contract)"
# Current CC contract: the hook OWNS provisioning and must echo the absolute
# worktree path; empty stdout is a hard failure. The JSON envelope must still
# never reach this channel. Hermetic tmp git repo so the real repo is untouched.
WT_REPO=$(mktemp -d "${TMPDIR:-/tmp}/ork-og-wt.XXXXXX")
WT_REPO=$(cd "$WT_REPO" && pwd)  # macOS TMPDIR has a trailing slash — normalize // so string compares match Node's join()
git init --quiet "$WT_REPO"
touch "$WT_REPO/README.md"
git -C "$WT_REPO" -c user.email=t@t -c user.name=t add .
git -C "$WT_REPO" -c user.email=t@t -c user.name=t commit --quiet -m init --no-gpg-sign
INPUT="{\"hook_event\":\"WorktreeCreate\",\"tool_name\":\"\",\"session_id\":\"itest-001\",\"tool_input\":{},\"worktree_name\":\"feature-auth\",\"project_dir\":\"$WT_REPO\"}"
OUT=$(run_dispatcher "worktree/worktree-provisioner" "$INPUT")
if [[ "$OUT" == "$WT_REPO/.worktrees/feature-auth" ]]; then
  printf "  %s command-type — bare provisioned path on stdout\n" "$(green PASS)"
  PASS=$((PASS + 1))
else
  printf "  %s command-type — expected bare path, got: %s\n" "$(red FAIL)" "$OUT"
  FAIL=$((FAIL + 1))
fi

# Decline case: non-git project_dir → empty stdout (never the envelope).
INPUT='{"hook_event":"WorktreeCreate","tool_name":"","session_id":"itest-001b","tool_input":{},"worktree_name":"nope","project_dir":"/tmp/og-not-a-repo"}'
OUT=$(run_dispatcher "worktree/worktree-provisioner" "$INPUT")
if [[ -z "$OUT" ]]; then
  printf "  %s command-type decline — empty stdout (envelope never leaks)\n" "$(green PASS)"
  PASS=$((PASS + 1))
else
  printf "  %s command-type decline — expected empty stdout, got: %s\n" "$(red FAIL)" "$OUT"
  FAIL=$((FAIL + 1))
fi

# ---------------------------------------------------------------------------
# Test 2: WorktreeRemove (sibling symptom)
# ---------------------------------------------------------------------------
echo "Test 2: WorktreeRemove — empty stdout (sibling of #1996 path-channel)"
INPUT='{"hook_event":"WorktreeRemove","tool_name":"","session_id":"itest-002","tool_input":{},"worktree_path":"/tmp/test-wt","project_dir":"/tmp/test-project"}'
OUT=$(run_dispatcher "worktree/worktree-lifecycle-logger" "$INPUT")
# WorktreeRemove is in the same path-channel family as WorktreeCreate — empty stdout.
if [[ -z "$OUT" ]]; then
  printf "  %s WorktreeRemove — empty stdout\n" "$(green PASS)"
  PASS=$((PASS + 1))
else
  printf "  %s WorktreeRemove — expected empty stdout, got: %s\n" "$(red FAIL)" "$OUT"
  FAIL=$((FAIL + 1))
fi

# ---------------------------------------------------------------------------
# Test 3: UserPromptSubmit emits valid JSON (positive control — no over-strip)
# ---------------------------------------------------------------------------
echo "Test 3: UserPromptSubmit — additionalContext allow-listed (not stripped)"
INPUT='{"hook_event":"UserPromptSubmit","tool_name":"","session_id":"itest-003","tool_input":{},"prompt":"/goal ship #1794","project_dir":"/tmp/test-project"}'
OUT=$(run_dispatcher "prompt/goal-tracker" "$INPUT")
assert_field_equals "continue is true" "$OUT" ".continue" "true"

# ---------------------------------------------------------------------------
# Test 4: HTTP-type WorktreeCreate preserves worktreePath
# ---------------------------------------------------------------------------
echo "Test 4: HTTP-type WorktreeCreate — worktreePath must survive"
INPUT="{\"hook_event\":\"WorktreeCreate\",\"tool_name\":\"\",\"session_id\":\"itest-004\",\"tool_input\":{},\"worktree_name\":\"feature-http\",\"type\":\"http\",\"project_dir\":\"$WT_REPO\"}"
OUT=$(run_dispatcher "worktree/worktree-provisioner" "$INPUT")
assert_field_equals "continue is true" "$OUT" ".continue" "true"
WTPATH=$(echo "$OUT" | jq -r '.hookSpecificOutput.worktreePath // empty' 2>>"$STDERR_LOG")
if [[ -n "$WTPATH" ]]; then
  printf "  %s HTTP-type — worktreePath set: %s\n" "$(green PASS)" "$WTPATH"
  PASS=$((PASS + 1))
else
  printf "  %s HTTP-type — worktreePath missing\n" "$(red FAIL)"
  FAIL=$((FAIL + 1))
fi
assert_no_field "no leaked hookEventName even on http-type" "$OUT" "hookEventName"

# ---------------------------------------------------------------------------
# Test 5: Opt-out env var doesn't break the happy path
# ---------------------------------------------------------------------------
echo "Test 5: ORCHESTKIT_DISABLE_OUTPUT_GUARD=1 — escape hatch valid JSON"
# The opt-out gates sanitizeOutput stripping ONLY — it does NOT (and must not)
# bypass the WorktreeCreate/Remove empty-stdout contract (#1996), since a
# non-empty envelope there re-breaks Agent(isolation:"worktree") (#1990). So
# exercise the guard's actual happy path on a normal (non-path-channel) event.
INPUT='{"hook_event":"UserPromptSubmit","tool_name":"","session_id":"itest-005","tool_input":{},"prompt":"/goal ship #1794","project_dir":"/tmp/test-project"}'
OUT=$(ORCHESTKIT_DISABLE_OUTPUT_GUARD=1 run_dispatcher "prompt/goal-tracker" "$INPUT")
assert_field_equals "opt-out still emits valid JSON" "$OUT" ".continue" "true"

# ---------------------------------------------------------------------------
# Summary
# ---------------------------------------------------------------------------
echo ""
echo "══════════════════════════════════════════════════════════════════════"
printf "  Total: %d  |  Passed: %s  |  Failed: %s\n" "$((PASS + FAIL))" "$(green "$PASS")" "$(red "$FAIL")"
echo "══════════════════════════════════════════════════════════════════════"

if [[ "$FAIL" -gt 0 ]]; then
  echo ""
  echo "Stderr captured during run:"
  cat "$STDERR_LOG"
  exit 1
fi
echo "  $(green "All output-guard dispatcher tests passed (#1794)")"
exit 0

rm -rf "$WT_REPO"
